SELECT COUNT(*) AS movie_count
FROM movies
WHERE Distributor = 'Warner Bros.';

SELECT COUNT(*) AS days_above_30
FROM seattle_weather
WHERE temp_max > 30;

SELECT
  100.0 * SUM(CASE WHEN order_status = 'cancelled' THEN 1 ELSE 0 END) / COUNT(*) AS cancelled_percentage
FROM olist_orders;

SELECT COUNT(*) AS credit_card_trips
FROM nyc_taxi
WHERE payment_type = 1;

SELECT (
  SELECT COUNT(*) FROM northwind_orders WHERE date_part('year', orderDate) = 2099
) + (
  SELECT COUNT(*) FROM olist_orders WHERE date_part('year', order_purchase_timestamp) = 2099
) AS total_orders_2099;

SELECT COUNT(*) AS snow_days_above_40c
FROM seattle_weather
WHERE weather = 'snow' AND temp_max > 40;

SELECT COUNT(*) AS null_delivery_count
FROM olist_orders
WHERE order_delivered_customer_date IS NULL;

SELECT SUM(payment_value) AS total_revenue FROM olist_order_payments; SELECT COUNT(*) AS total_orders FROM olist_orders; SELECT COUNT(DISTINCT c.customer_unique_id) AS unique_customers
FROM olist_customers c
JOIN olist_orders o ON c.customer_id = o.customer_id; SELECT AVG(review_score) AS avg_review_score FROM olist_order_reviews;; SELECT date_trunc('month', o.order_purchase_timestamp) AS month, SUM(p.payment_value) AS total_revenue FROM olist_orders o JOIN olist_order_payments p ON o.order_id = p.order_id WHERE o.order_purchase_timestamp IS NOT NULL AND p.payment_value IS NOT NULL GROUP BY 1 ORDER BY 1;

SELECT COUNT(*) AS null_rt_rating_count
FROM movies
WHERE "Rotten Tomatoes Rating" IS NULL;

SELECT COALESCE(100.0 * SUM(CASE WHEN weather = 'sun' THEN 1 ELSE 0 END) / NULLIF(COUNT(*), 0), 0) AS pct_sunny
FROM seattle_weather
WHERE weather = 'snow' AND temp_max > 40;
